SELECT ?attendance WHERE { 
  VALUES ?team { wd:Q213959 wd:Q82565 } .
  ?game wdt:P31 wd:Q4736619 ;
        wdt:P710 ?team ;
        wdt:P580 ?date ;
        wdt:P1110 ?attendance .
  FILTER (?date >= \"2013-10-12T00:00:00Z\"^^xsd:dateTime)
  FILTER (?date <= \"2013-10-19T00:00:00Z\"^^xsd:dateTime)
}
GROUP BY ?attendance
HAVING (COUNT(DISTINCT ?team) = 2)
ORDER BY ASC(xsd:integer(?attendance))
LIMIT 3

